40: /**
41:  * A {@link Window} that represents a time interval from {@code start} (inclusive) to {@code end}
42:  * (exclusive).
43:  */
44: @PublicEvolving
45: public class TimeWindow extends Window {
46: 
47:     private final long start;
48:     private final long end;
49: 
50:     public TimeWindow(long start, long end) {
51:         this.start = start;
52:         this.end = end;
53:     }
54: 
55:     /**
56:      * Gets the starting timestamp of the window. This is the first timestamp that belongs to this
57:      * window.
58:      *
59:      * @return The starting timestamp of this window.
60:      */
61:     public long getStart() {
62:         return start;
63:     }
64: 
65:     /**
66:      * Gets the end timestamp of this window. The end timestamp is exclusive, meaning it is the
67:      * first timestamp that does not belong to this window any more.
68:      *
69:      * @return The exclusive end timestamp of this window.
70:      */
71:     public long getEnd() {
72:         return end;
73:     }
74: 
75:     /**
76:      * Gets the largest timestamp that still belongs to this window.
77:      *
78:      * <p>This timestamp is identical to {@code getEnd() - 1}.
79:      *
80:      * @return The largest timestamp that still belongs to this window.
81:      * @see #getEnd()
82:      */
83:     @Override
84:     public long maxTimestamp() {
85:         return end - 1;
86:     }
87: 
88:     @Override
89:     public boolean equals(Object o) {
90:         if (this == o) {
91:             return true;
92:         }
93:         if (o == null || getClass() != o.getClass()) {
94:             return false;
95:         }
96: 
97:         TimeWindow window = (TimeWindow) o;
98: 
99:         return end == window.end && start == window.start;
100:     }
101: 
102:     @Override
103:     public int hashCode() {
104:         return MathUtils.longToIntWithBitMixing(start + end);
105:     }
106: 
107:     @Override
108:     public String toString() {
109:         return "TimeWindow{" + "start=" + start + ", end=" + end + '}';
110:     }
111: 
112:     /**
113:      * Returns {@code true} if this window intersects the given window or if this window is just
114:      * after or before the given window.
115:      */
116:     public boolean intersects(TimeWindow other) {
117:         return this.start <= other.end && this.end >= other.start;
118:     }
119: 
120:     /** Returns the minimal window covers both this window and the given window. */
121:     public TimeWindow cover(TimeWindow other) {
122:         return new TimeWindow(Math.min(start, other.start), Math.max(end, other.end));
123:     }
124: 
125:     // ------------------------------------------------------------------------
126:     // Serializer
127:     // ------------------------------------------------------------------------
128: 
129:     /** The serializer used to write the TimeWindow type. */
130:     public static class Serializer extends TypeSerializerSingleton<TimeWindow> {
131:         private static final long serialVersionUID = 1L;
132: 
133:         @Override
134:         public boolean isImmutableType() {
135:             return true;
136:         }
137: 
138:         @Override
139:         public TimeWindow createInstance() {
140:             return new TimeWindow(0L, 1L);
141:         }
142: 
143:         @Override
144:         public TimeWindow copy(TimeWindow from) {
145:             return from;
146:         }
147: 
148:         @Override
149:         public TimeWindow copy(TimeWindow from, TimeWindow reuse) {
150:             return from;
151:         }
152: 
153:         @Override
154:         public int getLength() {
155:             return Long.BYTES + Long.BYTES;
156:         }
157: 
158:         @Override
159:         public void serialize(TimeWindow record, DataOutputView target) throws IOException {
160:             target.writeLong(record.start);
161:             target.writeLong(record.end);
162:         }
163: 
164:         @Override
165:         public TimeWindow deserialize(DataInputView source) throws IOException {
166:             long start = source.readLong();
167:             long end = source.readLong();
168:             return new TimeWindow(start, end);
169:         }
170: 
171:         @Override
172:         public TimeWindow deserialize(TimeWindow reuse, DataInputView source) throws IOException {
173:             return deserialize(source);
174:         }
175: 
176:         @Override
177:         public void copy(DataInputView source, DataOutputView target) throws IOException {
178:             target.writeLong(source.readLong());
179:             target.writeLong(source.readLong());
180:         }
181: 
182:         // ------------------------------------------------------------------------
183: 
184:         @Override
185:         public TypeSerializerSnapshot<TimeWindow> snapshotConfiguration() {
186:             return new TimeWindowSerializerSnapshot();
187:         }
188: 
189:         /** Serializer configuration snapshot for compatibility and format evolution. */
190:         @SuppressWarnings("WeakerAccess")
191:         public static final class TimeWindowSerializerSnapshot
192:                 extends SimpleTypeSerializerSnapshot<TimeWindow> {
193: 
194:             public TimeWindowSerializerSnapshot() {
195:                 super(Serializer::new);
196:             }
197:         }
198:     }
